-- 3b. Restaurant descriptions (iştah açıcı kısa Türkçe tanıtımlar)
-- 004 migration daha önce çalışmamış olsa da seed bozulmasın diye defansif ALTER:
ALTER TABLE restaurant ADD COLUMN IF NOT EXISTS description TEXT;

UPDATE restaurant r
SET description = v.description
FROM (VALUES
    (1,  'Moda Caddesi''nde el yapımı dana köfteyle hazırlanan smash burgerler; çıtır patates ve ev yapımı sosların eşliğinde rahat bir buluşma noktası.'),
    (2,  'Doğu Anadolu''nun köklü ateş lezzetleri; meşe odununda pişen Adana, Urfa ve beyti ile kalabalık masaların vazgeçilmezi.'),
    (3,  'Bağdat Caddesi''ne bakan terasıyla günün balığını mevsim mezeleriyle buluşturan, klasik İstanbul meyhane ruhunda bir adres.'),
    (4,  'Karadeniz tereyağında kabarmış kapalı pide ve sulu Maltepe lahmacunuyla mahallenin sıcak fırın kokulu durağı.'),
    (5,  'Üsküdar sahilinin gölgeli avlusunda demli çay, taş fırın simidi ve sade bir Boğaz manzarası.'),
    (6,  'Söğütlüçeşme''de gece yarısına kadar açık kalan, limonu bol kokoreç ve dolma midyeleriyle Kadıköy''ün sokak klasiği.'),
    (7,  'Ataşehir''in koşuşturmasında üçüncü dalga kahve, ev yapımı tatlılar ve bol kitaplı huzurlu bir sığınak.'),
    (8,  'Suadiye''de dry-aged dana etleriyle pişen prime kesimler; gurmeleri özel rezervasyona davet eden modern bir steakhouse.'),
    (9,  'İçerenköy''ün öğle servisinde meşhur, döner ekmek arası ve kuzu pirzolasıyla gerçek esnaf lezzeti.'),
    (10, 'Altıntepe''de üç kuşaktır aynı tezgahta hazırlanan profiterol, ekler ve tuzlu tatlılarla nostalji dolu bir pastane.'),
    (11, 'Kalamış Marina''nın akşam ışıklarında Akdeniz mutfağına Fransız dokunuşları katan, brunch''tan gece yemeklerine uzanan brasserie.'),
    (12, 'Kozyatağı''nın merkezinde odun ateşinde pişen Napoli usulü pizza, ev yapımı pastalar ve İtalyan otları.'),
    (13, 'Kuzguncuk''un Boğaz''a inen sokağında her sabah taze çıkan ekşi mayalı ekmek ve poğaça kokuları.'),
    (14, 'Acıbadem''de geleneksel kazandibi, Maraş dondurması ve şıllıkla nesilden nesile aktarılan klasik tatlıcı.'),
    (15, 'El açması Kayseri mantısının, sarımsaklı yoğurt ve tereyağında pul biber sosuyla buluştuğu samimi mahalle dükkanı.'),
    (16, 'Hasanpaşa''da kömürde Tekirdağ köftesi, piyaz ve cacıkla klasik Türk öğle yemeği rutini.'),
    (17, 'Çengelköy''de el yapımı çikolata, trüf ve butik tatlılarla küçük ama özenli bir gurme atölyesi.'),
    (18, 'İdealtepe''de denizi gören terasta kömür ızgarada balık ve etin ev yapımı mezelerle buluşması.'),
    (19, 'Göztepe''nin sakin sokağında el yapımı taze makarna ve günün sosuyla küçük ama samimi bir İtalyan köşesi.'),
    (20, 'Ataşehir Bulvarı üzerinde sushi, sashimi ve ramen menüsüyle Uzakdoğu''ya kestirme bir yolculuk.'),
    (21, 'Caddebostan''da %100 bitkisel mutfak; kaju peyniri, ev yapımı seitan ve mevsim sebzeleriyle modern vegan bistro.'),
    (22, 'Suadiye''nin sahilinde günlük gelen taze balıklarla hazırlanan nigiri ve omakase deneyimi.'),
    (23, 'Moda''da brunch saatleri için yapılmış geniş kahvaltı tabakları, ev yapımı reçeller ve filtre kahve.'),
    (24, 'Bağdat Caddesi''nde gece kuşları için açık, limonu bol kokoreç ve dürümlerle alaturka sokak ruhu.'),
    (25, 'Caferağa''nın arka sokağında otantik tacolar, mole sosu ve serinleten margarita kombinasyonu.'),
    (26, 'Salacak''ta hamsi tava, mıhlama ve karalahana sarmasıyla Karadeniz mutfağının kıyıdaki adresi.'),
    (27, 'Vedat Günyol Caddesi''nde wok tavada hazırlanan pad thai, dim sum ve özel imza ramenleriyle Asya esintisi.'),
    (28, 'Bostancı''nın sessiz arka sokağında specialty kahve, single origin demlemeler ve ev yapımı pastalar.'),
    (29, 'Cevizli''de meşe odununda pişen tükürük köftesi, fırın patates ve sumaklı soğanla mütevazı bir ızgara durağı.'),
    (30, 'Erenköy''de tamamen bitkisel; çiğ tatlılar, fermente sebzeler ve kaju bazlı sıcak çorbalarla sağlıklı vegan menü.'),
    (31, 'Caddebostan sahilinde günlük taze yapraklarla hazırlanan poke bowl''lar, akıllı salata kombinasyonları.'),
    (32, 'Kozyatağı''nda Antep fıstıklı kebap, lahmacun ve baklavasıyla Güneydoğu''nun konsantre lezzetleri.'),
    (33, 'Suadiye sahilinde hafta sonu brunch ritüeli; menemen, smash avokado tost ve specialty filtre kahve.'),
    (34, 'Beşiktaş Köyiçi''nde Tekirdağ usulü kömür köfte, piyaz ve şalgamla klasik İstanbul lezzeti.'),
    (35, 'İstiklal Caddesi''nin tarihi binasında taş fırınında Roma tarzı uzun fermente pizzalar.'),
    (36, 'Bakırköy''ün eski ahşap konağında bakır sahanda yumurta ve serpme kahvaltı geleneği.'),
    (37, 'Küçükçekmece''de odun ateşinde dana antrikot ve kuzu pirzolayla mahalle yemeklerinin son hali.'),
    (38, 'Florya sahilinde dalga sesi eşliğinde günlük taze balık, mezeler ve ev yapımı rakı ikramları.'),
    (39, 'Asmalı Mescit''te bitkisel deney mutfağı; ferment, dehidrasyon ve mevsim sebzelerinin yaratıcı kombinasyonları.'),
    (40, 'Cihangir''de ışık dolu vitrini, single origin çekirdekleri ve ev yapımı pastalarla specialty kahve sığınağı.'),
    (41, 'Levent''in iş merkezleri arasında öğle servisinde maki, sashimi ve donburi seçenekleriyle hızlı sushi durağı.'),
    (42, 'Çırağan Caddesi''nde tex-mex; tacos, fajita ve gerçek margarita''yla canlı bir Meksika cantinası.'),
    (43, 'Etiler''de Asya, Hint ve Ortadoğu mutfaklarını harmanlayan modern füzyon menü.'),
    (44, 'Bebek sahilinde camlı terasla denizi gören brunch noktası; ev yapımı reçel ve filtre kahve.'),
    (45, 'Karaköy''ün arka sokağında kömürde kokoreç ve midye dolma; geceyi seven öğrenci ve sanatçıların adresi.'),
    (46, 'Galata Kulesi''nin gölgesinde tarihi bir binada uzun fermente espresso ve V60 demlemelerle butik kafe.'),
    (47, 'Halaskargazi Caddesi''nde Adana, urfa ve beyti çeşitleriyle yıllardır mahalleyi besleyen klasik kebap durağı.'),
    (48, 'İstiklal Caddesi''nde künefe, profiterol ve dondurma çeşitleriyle gece yarısına kadar açık tatlı durağı.'),
    (49, 'Yeşilköy''ün sakin sokağında bitkisel ev yemekleri, ekmekleri ve hatta vegan baklavası bile var.'),
    (50, 'Yeşilyurt''ta Anadolu''nun yedi bölgesinden seçme yemeklerin günlük menüde döndüğü modern bir grill restaurant.')
) AS v(rid, description)
WHERE r.restaurant_id = v.rid;

