-- 11. Reviews — yeni şema (Lezzet/Servis/Ambiyans), 50 restoran × 10 yorum
-- Migration sırası 005'ten önce çalıştığı için review tablosunu burada inline
-- olarak yeni şemaya göre yeniden kuruyoruz. (005 daha sonra çalışırsa
-- DROP+CREATE'ini tekrarlayıp veriyi temizler — buna dikkat.)

DROP TABLE IF EXISTS review CASCADE;

CREATE TABLE review (
    review_id        SERIAL PRIMARY KEY,
    restaurant_id    INT NOT NULL,
    user_id          INT NOT NULL,
    content          TEXT,
    rating_taste     INT DEFAULT NULL,
    rating_service   INT DEFAULT NULL,
    rating_attitude  INT DEFAULT NULL,
    created_at       TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_review_restaurant FOREIGN KEY (restaurant_id) REFERENCES restaurant(restaurant_id) ON DELETE CASCADE,
    CONSTRAINT fk_review_user       FOREIGN KEY (user_id)       REFERENCES "user"(user_id)         ON DELETE CASCADE,
    CONSTRAINT chk_rating_taste     CHECK (rating_taste    IS NULL OR (rating_taste    BETWEEN 1 AND 5)),
    CONSTRAINT chk_rating_service   CHECK (rating_service  IS NULL OR (rating_service  BETWEEN 1 AND 5)),
    CONSTRAINT chk_rating_attitude  CHECK (rating_attitude IS NULL OR (rating_attitude BETWEEN 1 AND 5))
);

CREATE INDEX idx_review_restaurant_created_at ON review (restaurant_id, created_at DESC);

